       public RetCode mama( int startIdx,
                            int endIdx,
                            double inReal[],
                            double optInFastLimit,
                            double optInSlowLimit,
                            MInteger outBegIdx,
                            MInteger outNBElement,
                            double outMAMA[],
                            double outFAMA[] )
       {
          int outIdx;
          int i;
          int lookbackTotal;
          int today;
          double tempReal;
          double tempReal2;
          double adjustedPrevPeriod;
          double period;
          int trailingWMAIdx;
          double periodWMASum;
          double periodWMASub;
          double trailingWMAValue;
          double smoothedValue;
          double a;
          double b;
          double hilbertTempReal;
          int hilbertIdx;
          double[] detrender_Odd = new double[3];
          double[] detrender_Even = new double[3];
          double detrender;
          double prev_detrender_Odd;
          double prev_detrender_Even;
          double prev_detrender_input_Odd;
          double prev_detrender_input_Even;
          double[] Q1_Odd = new double[3];
          double[] Q1_Even = new double[3];
          double Q1;
          double prev_Q1_Odd;
          double prev_Q1_Even;
          double prev_Q1_input_Odd;
          double prev_Q1_input_Even;
          double[] jI_Odd = new double[3];
          double[] jI_Even = new double[3];
          double jI;
          double prev_jI_Odd;
          double prev_jI_Even;
          double prev_jI_input_Odd;
          double prev_jI_input_Even;
          double[] jQ_Odd = new double[3];
          double[] jQ_Even = new double[3];
          double jQ;
          double prev_jQ_Odd;
          double prev_jQ_Even;
          double prev_jQ_input_Odd;
          double prev_jQ_input_Even;
          double Q2;
          double I2;
          double prevQ2;
          double prevI2;
          double Re;
          double Im;
          double I1ForOddPrev2;
          double I1ForOddPrev3;
          double I1ForEvenPrev2;
          double I1ForEvenPrev3;
          double rad2Deg;
          double mama;
          double fama;
          double todayValue;
          double prevPhase;
          if( startIdx < 0 ) {
             return RetCode.OutOfRangeStartIndex ;
          }
          if( (endIdx < 0) || (endIdx < startIdx)) {
             return RetCode.OutOfRangeEndIndex ;
          }
          a = 0.0962;
          b = 0.5769;
          rad2Deg = (180.0/(4.0*Math.atan(1)));
          lookbackTotal = (32+this.unstablePeriod[FuncUnstId.Mama.ordinal()]);
          if( (startIdx<lookbackTotal) ) {
             startIdx = lookbackTotal;
          }
          if( (startIdx>endIdx) ) {
             outBegIdx.value = 0;
             outNBElement.value = 0;
             return RetCode.Success ;
          }
          outBegIdx.value = startIdx;
          trailingWMAIdx = (startIdx-lookbackTotal);
          today = trailingWMAIdx;
          tempReal = inReal[today++];
          periodWMASub = tempReal;
          periodWMASum = tempReal;
          tempReal = inReal[today++];
          periodWMASub += tempReal;
          periodWMASum += (tempReal*2.0);
          tempReal = inReal[today++];
          periodWMASub += tempReal;
          periodWMASum += (tempReal*3.0);
          trailingWMAValue = 0.0;
          i = 9;
          do {
             tempReal = inReal[today++];
             periodWMASub += tempReal;
             periodWMASub -= trailingWMAValue;
             periodWMASum += (tempReal*4.0);
             trailingWMAValue = inReal[trailingWMAIdx++];
             smoothedValue = (periodWMASum*0.1);
             periodWMASum -= periodWMASub;
          } while( (--i!=0) );
          hilbertIdx = 0;
          period = 0.0;
          outIdx = 0;
          prevQ2 = 0.0;
          prevI2 = prevQ2;
          Im = 0.0;
          Re = Im;
          fama = 0.0;
          mama = fama;
          I1ForEvenPrev3 = 0.0;
          I1ForOddPrev3 = I1ForEvenPrev3;
          I1ForEvenPrev2 = 0.0;
          I1ForOddPrev2 = I1ForEvenPrev2;
          prevPhase = 0.0;
          while( (today<=endIdx) ) {
             adjustedPrevPeriod = ((0.075*period)+0.54);
             todayValue = inReal[today];
             periodWMASub += todayValue;
             periodWMASub -= trailingWMAValue;
             periodWMASum += (todayValue*4.0);
             trailingWMAValue = inReal[trailingWMAIdx++];
             smoothedValue = (periodWMASum*0.1);
             periodWMASum -= periodWMASub;
             if( ((today%2)==0) ) {
                hilbertTempReal = (a*smoothedValue);
                detrender = (0-detrender_Even[hilbertIdx]);
                detrender_Even[hilbertIdx] = hilbertTempReal;
                detrender += hilbertTempReal;
                detrender -= prev_detrender_Even;
                prev_detrender_Even = (b*prev_detrender_input_Even);
                detrender += prev_detrender_Even;
                prev_detrender_input_Even = smoothedValue;
                detrender *= adjustedPrevPeriod;
                hilbertTempReal = (a*detrender);
                Q1 = (0-Q1_Even[hilbertIdx]);
                Q1_Even[hilbertIdx] = hilbertTempReal;
                Q1 += hilbertTempReal;
                Q1 -= prev_Q1_Even;
                prev_Q1_Even = (b*prev_Q1_input_Even);
                Q1 += prev_Q1_Even;
                prev_Q1_input_Even = detrender;
                Q1 *= adjustedPrevPeriod;
                hilbertTempReal = (a*I1ForEvenPrev3);
                jI = (0-jI_Even[hilbertIdx]);
                jI_Even[hilbertIdx] = hilbertTempReal;
                jI += hilbertTempReal;
                jI -= prev_jI_Even;
                prev_jI_Even = (b*prev_jI_input_Even);
                jI += prev_jI_Even;
                prev_jI_input_Even = I1ForEvenPrev3;
                jI *= adjustedPrevPeriod;
                hilbertTempReal = (a*Q1);
                jQ = (0-jQ_Even[hilbertIdx]);
                jQ_Even[hilbertIdx] = hilbertTempReal;
                jQ += hilbertTempReal;
                jQ -= prev_jQ_Even;
                prev_jQ_Even = (b*prev_jQ_input_Even);
                jQ += prev_jQ_Even;
                prev_jQ_input_Even = Q1;
                jQ *= adjustedPrevPeriod;
                if( (++hilbertIdx==3) ) {
                   hilbertIdx = 0;
                }
                Q2 = ((0.2*(Q1+jI))+(0.8*prevQ2));
                I2 = ((0.2*(I1ForEvenPrev3-jQ))+(0.8*prevI2));
                I1ForOddPrev3 = I1ForOddPrev2;
                I1ForOddPrev2 = detrender;
                if( (I1ForEvenPrev3!=0.0) ) {
                   tempReal2 = (Math.atan((Q1/I1ForEvenPrev3))*rad2Deg);
                } else {
                   tempReal2 = 0.0;
                }
             } else {
                hilbertTempReal = (a*smoothedValue);
                detrender = (0-detrender_Odd[hilbertIdx]);
                detrender_Odd[hilbertIdx] = hilbertTempReal;
                detrender += hilbertTempReal;
                detrender -= prev_detrender_Odd;
                prev_detrender_Odd = (b*prev_detrender_input_Odd);
                detrender += prev_detrender_Odd;
                prev_detrender_input_Odd = smoothedValue;
                detrender *= adjustedPrevPeriod;
                hilbertTempReal = (a*detrender);
                Q1 = (0-Q1_Odd[hilbertIdx]);
                Q1_Odd[hilbertIdx] = hilbertTempReal;
                Q1 += hilbertTempReal;
                Q1 -= prev_Q1_Odd;
                prev_Q1_Odd = (b*prev_Q1_input_Odd);
                Q1 += prev_Q1_Odd;
                prev_Q1_input_Odd = detrender;
                Q1 *= adjustedPrevPeriod;
                hilbertTempReal = (a*I1ForOddPrev3);
                jI = (0-jI_Odd[hilbertIdx]);
                jI_Odd[hilbertIdx] = hilbertTempReal;
                jI += hilbertTempReal;
                jI -= prev_jI_Odd;
                prev_jI_Odd = (b*prev_jI_input_Odd);
                jI += prev_jI_Odd;
                prev_jI_input_Odd = I1ForOddPrev3;
                jI *= adjustedPrevPeriod;
                hilbertTempReal = (a*Q1);
                jQ = (0-jQ_Odd[hilbertIdx]);
                jQ_Odd[hilbertIdx] = hilbertTempReal;
                jQ += hilbertTempReal;
                jQ -= prev_jQ_Odd;
                prev_jQ_Odd = (b*prev_jQ_input_Odd);
                jQ += prev_jQ_Odd;
                prev_jQ_input_Odd = Q1;
                jQ *= adjustedPrevPeriod;
                Q2 = ((0.2*(Q1+jI))+(0.8*prevQ2));
                I2 = ((0.2*(I1ForOddPrev3-jQ))+(0.8*prevI2));
                I1ForEvenPrev3 = I1ForEvenPrev2;
                I1ForEvenPrev2 = detrender;
                if( (I1ForOddPrev3!=0.0) ) {
                   tempReal2 = (Math.atan((Q1/I1ForOddPrev3))*rad2Deg);
                } else {
                   tempReal2 = 0.0;
                }
             }
             tempReal = (prevPhase-tempReal2);
             prevPhase = tempReal2;
             if( (tempReal<1.0) ) {
                tempReal = 1.0;
             }
             if( (tempReal>1.0) ) {
                tempReal = (optInFastLimit/tempReal);
                if( (tempReal<optInSlowLimit) ) {
                   tempReal = optInSlowLimit;
                }
             } else {
                tempReal = optInFastLimit;
             }
             mama = ((tempReal*todayValue)+((1-tempReal)*mama));
             tempReal *= 0.5;
             fama = ((tempReal*mama)+((1-tempReal)*fama));
             if( (today>=startIdx) ) {
                outMAMA[outIdx] = mama;
                outFAMA[outIdx++] = fama;
             }
             Re = ((0.2*((I2*prevI2)+(Q2*prevQ2)))+(0.8*Re));
             Im = ((0.2*((I2*prevQ2)-(Q2*prevI2)))+(0.8*Im));
             prevQ2 = Q2;
             prevI2 = I2;
             tempReal = period;
             if( ((Im!=0.0)&&(Re!=0.0)) ) {
                period = (360.0/(Math.atan((Im/Re))*rad2Deg));
             }
             tempReal2 = (1.5*tempReal);
             if( (period>tempReal2) ) {
                period = tempReal2;
             }
             tempReal2 = (0.67*tempReal);
             if( (period<tempReal2) ) {
                period = tempReal2;
             }
             if( (period<6) ) {
                period = 6;
             } else if( (period>50) ) {
                period = 50;
             }
             period = ((0.2*period)+(0.8*tempReal));
             today += 1;
          }
          outNBElement.value = outIdx;
          return RetCode.Success ;
       }
