       public RetCode ultosc( int startIdx,
                              int endIdx,
                              double inHigh[],
                              double inLow[],
                              double inClose[],
                              int optInTimePeriod1,
                              int optInTimePeriod2,
                              int optInTimePeriod3,
                              MInteger outBegIdx,
                              MInteger outNBElement,
                              double outReal[] )
       {
          double a1Total;
          double a2Total;
          double a3Total;
          double b1Total;
          double b2Total;
          double b3Total;
          double trueLow;
          double trueRange;
          double closeMinusTrueLow;
          double tempDouble;
          double output;
          double tempHT;
          double tempLT;
          double tempCY;
          int lookbackTotal;
          int longestPeriod;
          int longestIndex;
          int i;
          int j;
          int today;
          int outIdx;
          int trailingIdx1;
          int trailingIdx2;
          int trailingIdx3;
          int[] usedFlag = new int[3];
          int[] periods = new int[3];
          int[] sortedPeriods = new int[3];
          if( startIdx < 0 ) {
             return RetCode.OutOfRangeStartIndex ;
          }
          if( (endIdx < 0) || (endIdx < startIdx)) {
             return RetCode.OutOfRangeEndIndex ;
          }
          outBegIdx.value = 0;
          outNBElement.value = 0;
          periods[0] = optInTimePeriod1;
          periods[1] = optInTimePeriod2;
          periods[2] = optInTimePeriod3;
          usedFlag[0] = 0;
          usedFlag[1] = 0;
          usedFlag[2] = 0;
          for( i = 0; (i<3); i += 1 ) {
             longestPeriod = 0;
             longestIndex = 0;
             for( j = 0; (j<3); j += 1 ) {
                if( ((usedFlag[j]==0)&&(periods[j]>longestPeriod)) ) {
                   longestPeriod = periods[j];
                   longestIndex = j;
                }
             }
             usedFlag[longestIndex] = 1;
             sortedPeriods[i] = longestPeriod;
          }
          optInTimePeriod1 = sortedPeriods[2];
          optInTimePeriod2 = sortedPeriods[1];
          optInTimePeriod3 = sortedPeriods[0];
          lookbackTotal = ultoscLookback(optInTimePeriod1, optInTimePeriod2, optInTimePeriod3);
          if( (startIdx<lookbackTotal) ) {
             startIdx = lookbackTotal;
          }
          if( (startIdx>endIdx) ) {
             return RetCode.Success ;
          }
          a1Total = 0;
          b1Total = 0;
          for( i = ((startIdx-optInTimePeriod1)+1); (i<startIdx); i += 1 ) {
             tempLT = inLow[i];
             tempHT = inHigh[i];
             tempCY = inClose[(i-1)];
             trueLow = Math.min(tempLT, tempCY);
             closeMinusTrueLow = (inClose[i]-trueLow);
             trueRange = (tempHT-tempLT);
             tempDouble = Math.abs((tempCY-tempHT));
             if( (tempDouble>trueRange) ) {
                trueRange = tempDouble;
             }
             tempDouble = Math.abs((tempCY-tempLT));
             if( (tempDouble>trueRange) ) {
                trueRange = tempDouble;
             }
             a1Total += closeMinusTrueLow;
             b1Total += trueRange;
          }
          a2Total = 0;
          b2Total = 0;
          for( i = ((startIdx-optInTimePeriod2)+1); (i<startIdx); i += 1 ) {
             tempLT = inLow[i];
             tempHT = inHigh[i];
             tempCY = inClose[(i-1)];
             trueLow = Math.min(tempLT, tempCY);
             closeMinusTrueLow = (inClose[i]-trueLow);
             trueRange = (tempHT-tempLT);
             tempDouble = Math.abs((tempCY-tempHT));
             if( (tempDouble>trueRange) ) {
                trueRange = tempDouble;
             }
             tempDouble = Math.abs((tempCY-tempLT));
             if( (tempDouble>trueRange) ) {
                trueRange = tempDouble;
             }
             a2Total += closeMinusTrueLow;
             b2Total += trueRange;
          }
          a3Total = 0;
          b3Total = 0;
          for( i = ((startIdx-optInTimePeriod3)+1); (i<startIdx); i += 1 ) {
             tempLT = inLow[i];
             tempHT = inHigh[i];
             tempCY = inClose[(i-1)];
             trueLow = Math.min(tempLT, tempCY);
             closeMinusTrueLow = (inClose[i]-trueLow);
             trueRange = (tempHT-tempLT);
             tempDouble = Math.abs((tempCY-tempHT));
             if( (tempDouble>trueRange) ) {
                trueRange = tempDouble;
             }
             tempDouble = Math.abs((tempCY-tempLT));
             if( (tempDouble>trueRange) ) {
                trueRange = tempDouble;
             }
             a3Total += closeMinusTrueLow;
             b3Total += trueRange;
          }
          today = startIdx;
          outIdx = 0;
          trailingIdx1 = ((today-optInTimePeriod1)+1);
          trailingIdx2 = ((today-optInTimePeriod2)+1);
          trailingIdx3 = ((today-optInTimePeriod3)+1);
          while( (today<=endIdx) ) {
             tempLT = inLow[today];
             tempHT = inHigh[today];
             tempCY = inClose[(today-1)];
             trueLow = Math.min(tempLT, tempCY);
             closeMinusTrueLow = (inClose[today]-trueLow);
             trueRange = (tempHT-tempLT);
             tempDouble = Math.abs((tempCY-tempHT));
             if( (tempDouble>trueRange) ) {
                trueRange = tempDouble;
             }
             tempDouble = Math.abs((tempCY-tempLT));
             if( (tempDouble>trueRange) ) {
                trueRange = tempDouble;
             }
             a1Total += closeMinusTrueLow;
             a2Total += closeMinusTrueLow;
             a3Total += closeMinusTrueLow;
             b1Total += trueRange;
             b2Total += trueRange;
             b3Total += trueRange;
             output = 0.0;
             if( !((((0-0.00000001)<b1Total)&&(b1Total<0.00000001))) ) {
                output += (4.0*(a1Total/b1Total));
             }
             if( !((((0-0.00000001)<b2Total)&&(b2Total<0.00000001))) ) {
                output += (2.0*(a2Total/b2Total));
             }
             if( !((((0-0.00000001)<b3Total)&&(b3Total<0.00000001))) ) {
                output += (a3Total/b3Total);
             }
             tempLT = inLow[trailingIdx1];
             tempHT = inHigh[trailingIdx1];
             tempCY = inClose[(trailingIdx1-1)];
             trueLow = Math.min(tempLT, tempCY);
             closeMinusTrueLow = (inClose[trailingIdx1]-trueLow);
             trueRange = (tempHT-tempLT);
             tempDouble = Math.abs((tempCY-tempHT));
             if( (tempDouble>trueRange) ) {
                trueRange = tempDouble;
             }
             tempDouble = Math.abs((tempCY-tempLT));
             if( (tempDouble>trueRange) ) {
                trueRange = tempDouble;
             }
             a1Total -= closeMinusTrueLow;
             b1Total -= trueRange;
             tempLT = inLow[trailingIdx2];
             tempHT = inHigh[trailingIdx2];
             tempCY = inClose[(trailingIdx2-1)];
             trueLow = Math.min(tempLT, tempCY);
             closeMinusTrueLow = (inClose[trailingIdx2]-trueLow);
             trueRange = (tempHT-tempLT);
             tempDouble = Math.abs((tempCY-tempHT));
             if( (tempDouble>trueRange) ) {
                trueRange = tempDouble;
             }
             tempDouble = Math.abs((tempCY-tempLT));
             if( (tempDouble>trueRange) ) {
                trueRange = tempDouble;
             }
             a2Total -= closeMinusTrueLow;
             b2Total -= trueRange;
             tempLT = inLow[trailingIdx3];
             tempHT = inHigh[trailingIdx3];
             tempCY = inClose[(trailingIdx3-1)];
             trueLow = Math.min(tempLT, tempCY);
             closeMinusTrueLow = (inClose[trailingIdx3]-trueLow);
             trueRange = (tempHT-tempLT);
             tempDouble = Math.abs((tempCY-tempHT));
             if( (tempDouble>trueRange) ) {
                trueRange = tempDouble;
             }
             tempDouble = Math.abs((tempCY-tempLT));
             if( (tempDouble>trueRange) ) {
                trueRange = tempDouble;
             }
             a3Total -= closeMinusTrueLow;
             b3Total -= trueRange;
             outReal[outIdx] = (100.0*(output/7.0));
             outIdx += 1;
             today += 1;
             trailingIdx1 += 1;
             trailingIdx2 += 1;
             trailingIdx3 += 1;
          }
          outNBElement.value = outIdx;
          outBegIdx.value = startIdx;
          return RetCode.Success ;
       }
